import{a as e}from"./chunks/checklist.Dd30d9YA.js";import{C as a,o as r,c as s,a2 as d,E as n,k as l}from"./chunks/framework.TWA1q3r6.js";const q=JSON.parse('{"title":"🗣️ 1-3Y · 语言爆发期","description":"","frontmatter":{"title":"🗣️ 1-3Y · 语言爆发期"},"headers":[],"relativePath":"stages/1-3y.md","filePath":"stages/1-3y.md"}'),i={name:"stages/1-3y.md"},b=Object.assign(i,{setup(u){return(h,t)=>{const o=a("ChecklistTable");return r(),s("div",null,[t[0]||(t[0]=d('<h1 id="🗣️-1-3y-·-语言爆发期" tabindex="-1">🗣️ 1-3Y · 语言爆发期 <a class="header-anchor" href="#🗣️-1-3y-·-语言爆发期" aria-label="Permalink to &quot;🗣️ 1-3Y · 语言爆发期&quot;">​</a></h1><blockquote><p>从 mama 到&quot;妈妈我不要这个我要那个为什么为什么为什么&quot;。</p><p>语言像瀑布一样涌出来。户外跑跑跑，绘本翻翻翻，泥巴捏捏捏。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>语言</td><td><strong>亲子共读 + 延展对话</strong></td><td>每天15min共读 → 3岁词汇量差3倍</td><td>15-30min/天</td><td>AAP</td></tr><tr><td>大运动</td><td><strong>户外无动力探索</strong></td><td>攀爬/跑/跳 = 前庭+本体感觉自然整合</td><td>每天≥1h户外</td><td>AAP</td></tr><tr><td>精细运动</td><td><strong>涂鸦 / 黏土 / 撕纸</strong></td><td>手指小肌群精细控制 → 为握笔书写做准备</td><td>融入日常玩耍</td><td>—</td></tr><tr><td>社会情感</td><td><strong>情绪命名</strong> Emotion Labeling</td><td>&quot;你现在很生气&quot; → 前额叶调节杏仁核回路建立</td><td>情绪发生时即时</td><td>Lieberman</td></tr><tr><td>自主性</td><td><strong>如厕训练</strong>（18-24M窗口）</td><td>括约肌成熟 + 模仿意愿 = 窗口期</td><td>跟随孩子信号</td><td>AAP</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">科学边界 🔬</p><p>1-3Y是&quot;感统训练&quot;营销重灾区。无医学诊断的感统训练没有RCT支持。真正的感觉统合在户外自由玩耍中就能自然完成 —— 踩水坑、爬土坡、滚草地，比任何课程都有效。</p></div><hr><h2 id="📋-装备采购清单" tabindex="-1">📋 装备采购清单 <a class="header-anchor" href="#📋-装备采购清单" aria-label="Permalink to &quot;📋 装备采购清单&quot;">​</a></h2>',8)),n(o,{stage:"1-3y",categories:l(e)},null,8,["categories"]),t[1]||(t[1]=d('<div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>早教机/点读笔（高端款）</strong> — 2岁前零屏幕，2-5岁≤1h/天。人际互动效果远大于设备。替代：真人共读</li><li><strong>&quot;右脑开发&quot;闪卡</strong> — &quot;右脑开发&quot;这个概念本身就没有RCT支持。替代：对话 + 绘本</li><li><strong>感统训练课（无诊断）</strong> — 无医学诊断的感统训练无RCT。替代：自由玩耍 + 户外</li></ul></div><hr><h2 id="📚-推荐绘本-语言爆发期" tabindex="-1">📚 推荐绘本：语言爆发期 <a class="header-anchor" href="#📚-推荐绘本-语言爆发期" aria-label="Permalink to &quot;📚 推荐绘本：语言爆发期&quot;">​</a></h2><blockquote><p>语言像瀑布一样涌出来的阶段——绘本是最好的词汇加速器。AAP建议每天亲子共读至少15分钟。</p></blockquote><table tabindex="0"><thead><tr><th>绘本</th><th>语言</th><th>为什么适合这个阶段</th><th>亲子共读要点</th></tr></thead><tbody><tr><td><em>We&#39;re Going on a Bear Hunt</em> 🐻</td><td>EN</td><td>Michael Rosen，节奏感+拟声词+冒险叙事</td><td>全家一起演，&quot;We can&#39;t go over it...&quot;</td></tr><tr><td><em>The Gruffalo</em> 🦔</td><td>EN/中</td><td>Julia Donaldson押韵故事，逻辑+幽默+想象力</td><td>用不同声音扮演每个角色</td></tr><tr><td><em>Guess How Much I Love You</em> 💚</td><td>EN/中</td><td>&quot;I love you to the moon&quot;——情感表达范本</td><td>睡前仪式固定用书</td></tr><tr><td><em>Owl Babies</em> 🦉</td><td>EN</td><td>分离焦虑主题，&quot;I want my mummy!&quot;经典共情</td><td>&quot;妈妈会回来的&quot;配合拥抱</td></tr><tr><td><em>The Tiger Who Came to Tea</em> 🐯</td><td>EN</td><td>Judith Kerr，想象力+日常场景+幽默</td><td>&quot;如果老虎来我们家喝茶...&quot;</td></tr><tr><td><em>Each Peach Pear Plum</em> 🍑</td><td>EN</td><td>Janet &amp; Allan Ahlberg，I Spy游戏+韵律</td><td>每页找隐藏角色</td></tr><tr><td><em>From Head to Toe</em> (Eric Carle)</td><td>EN/中</td><td>动物动作模仿，&quot;Can you do it? I can do it!&quot;</td><td>每页跟着做动作</td></tr><tr><td><em>小鸡球球成长系列</em> 🐥</td><td>中</td><td>入山智，日常场景(洗澡/睡觉/交朋友)</td><td>对照生活场景延展对话</td></tr><tr><td><em>宫西达也恐龙系列</em> 🦖</td><td>中</td><td>《你看起来好像很好吃》等，情感+想象力</td><td>&quot;你觉得霸王龙为什么哭了？&quot;</td></tr><tr><td><em>小熊很忙</em> 系列</td><td>中/EN</td><td>Benji Davies，机关书+职业认知+动手操作</td><td>推/拉/转每个机关</td></tr><tr><td><em>No, David!</em> 🚫</td><td>EN/中</td><td>David Shannon，调皮共鸣+&quot;但妈妈还是爱你&quot;</td><td>&quot;David做了什么？你也这样吗？&quot;</td></tr><tr><td><em>Chicka Chicka Boom Boom</em> 🌴</td><td>EN</td><td>字母认知+节奏+韵律，英语启蒙首选</td><td>打节拍念，像唱歌一样</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">📖 共读不是&quot;读完&quot;，是&quot;聊起来&quot;</p><p>AAP推荐的<strong>延展对话</strong>比念故事更重要：念一句→停下来→问&quot;你觉得呢？&quot;→等孩子回应→延展他的回答。Hart &amp; Risley的研究发现，3岁时词汇量差异可达<strong>3倍</strong>，差距的核心不是读了多少本书，而是<strong>对话的回合数</strong>。</p></div><hr><h2 id="🌟-1y-成长多巴胺准备金" tabindex="-1">🌟 1Y+ 成长多巴胺准备金 <a class="header-anchor" href="#🌟-1y-成长多巴胺准备金" aria-label="Permalink to &quot;🌟 1Y+ 成长多巴胺准备金&quot;">​</a></h2><blockquote><p>把发育刚需变成亲子好时光。</p></blockquote><table tabindex="0"><thead><tr><th>物品</th><th>为什么值得</th><th>参考方向</th><th>预算</th></tr></thead><tbody><tr><td>🌧️ 儿童雨靴+雨衣</td><td>雨天 = 最佳感官探索，踩水坑是天然感统训练</td><td>Crocs / Petit Bateau</td><td>¥100-300</td></tr><tr><td>🌱 微型园艺工具</td><td>种一棵草莓 = 观察+等待+因果关系的真实课</td><td>Burgon &amp; Ball / 宜家</td><td>¥30-150</td></tr><tr><td>✏️ 可书写墙</td><td>涂鸦是精细运动核心通道，涂鸦墙比画纸自由太多</td><td>3M白板贴 / 黑板漆</td><td>¥100-300</td></tr><tr><td>⛺ 露营入门装备</td><td>3Y+每年4次户外过夜 = 48h无屏幕自然教育</td><td>牧高笛 / 挪客</td><td>¥500-2,000</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">多巴胺准备金的筛选逻辑 💡</p><p>每一项至少满足以下两个条件：<strong>高频使用</strong>（每周≥3次）、<strong>审美溢价合理</strong>（同品类价差50%以内）、<strong>附带发展价值</strong>（服务于户外/精细运动/感官探索）。</p></div>',11))])}}});export{q as __pageData,b as default};
